import type { Field } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/**
 * Maps a DMMF field to its TypeScript type representation.
 * Handles scalars, enums, lists, and nullability.
 */
export function fieldToTsType(field: Field): string {
  let baseType: string

  if (field.kind === 'enum') {
    baseType = field.type
  } else {
    baseType = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  }

  if (field.isList) {
    baseType = `${baseType}[]`
  }

  if (!field.isRequired) {
    baseType = `${baseType} | null`
  }

  return baseType
}

