import type { DatamodelEnum } from '@prisma/dmmf'

/** Generates TypeScript string union types for all Prisma enums. */
export function generateEnumTypes(enums: readonly DatamodelEnum[]): string {
  if (enums.length === 0) return ''

  return enums
    .map((enumDef) => {
      const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
      return `export type ${enumDef.name} = ${values}`
    })
    .join('\n\n')
}

