import type { Model } from '@prisma/dmmf'

function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/** Generates the main PrismaRestClient class that aggregates all model delegates. */
export function generateClientClass(models: readonly Model[]): string {
  const delegateImports = models.map((m) => `${m.name}Delegate`).join(', ')
  const importStatement = `import { ${delegateImports} } from './delegates'`

  const properties = models.map((m) => `  readonly ${toCamelCase(m.name)}: ${m.name}Delegate`).join('\n')

  const assignments = models
    .map((m) => `    this.${toCamelCase(m.name)} = new ${m.name}Delegate(config.baseUrl, headers)`)
    .join('\n')

  return `${importStatement}

export class PrismaRestClient {
${properties}

  constructor(config: { baseUrl: string; headers?: Record<string, string> }) {
    const headers = config.headers ?? {}
${assignments}
  }
}
`
}

