import type { Field } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { fieldToTsType } from './type-mapping'

function makeField(overrides: Partial<Field>): Field {
  return {
    kind: 'scalar',
    name: 'test',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  } as Field
}

describe('fieldToTsType', () => {
  test('maps String to string', () => {
    expect(fieldToTsType(makeField({ type: 'String' }))).toBe('string')
  })

  test('maps Int to number', () => {
    expect(fieldToTsType(makeField({ type: 'Int' }))).toBe('number')
  })

  test('maps Float to number', () => {
    expect(fieldToTsType(makeField({ type: 'Float' }))).toBe('number')
  })

  test('maps Boolean to boolean', () => {
    expect(fieldToTsType(makeField({ type: 'Boolean' }))).toBe('boolean')
  })

  test('maps DateTime to string', () => {
    expect(fieldToTsType(makeField({ type: 'DateTime' }))).toBe('string')
  })

  test('maps BigInt to bigint', () => {
    expect(fieldToTsType(makeField({ type: 'BigInt' }))).toBe('bigint')
  })

  test('maps Decimal to string', () => {
    expect(fieldToTsType(makeField({ type: 'Decimal' }))).toBe('string')
  })

  test('maps Json to unknown', () => {
    expect(fieldToTsType(makeField({ type: 'Json' }))).toBe('unknown')
  })

  test('maps Bytes to string', () => {
    expect(fieldToTsType(makeField({ type: 'Bytes' }))).toBe('string')
  })

  test('handles optional fields with | null', () => {
    expect(fieldToTsType(makeField({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  test('handles list fields with []', () => {
    expect(fieldToTsType(makeField({ type: 'String', isList: true }))).toBe('string[]')
  })

  test('handles optional list fields', () => {
    expect(fieldToTsType(makeField({ type: 'Int', isList: true, isRequired: false }))).toBe('number[] | null')
  })

  test('maps enum fields to their type name', () => {
    expect(fieldToTsType(makeField({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  test('maps unknown scalar types to unknown', () => {
    expect(fieldToTsType(makeField({ type: 'SomeUnknownType' }))).toBe('unknown')
  })
})

