import { describe, expect, test } from 'vitest'

import { generateEnumTypes } from './generate-enum-types'

describe('generateEnumTypes', () => {
  test('generates string union for a single enum', () => {
    const enums: DatamodelEnum[] = [
      {
        name: 'Role',
        values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }],
      },
    ]

    expect(generateEnumTypes(enums)).toBe("export type Role = 'ADMIN' | 'USER'")
  })

  test('generates multiple enums separated by blank lines', () => {
    const enums: DatamodelEnum[] = [
      {
        name: 'Role',
        values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }],
      },
      {
        name: 'Status',
        values: [
          { name: 'DRAFT', dbName: null },
          { name: 'PUBLISHED', dbName: null },
          { name: 'ARCHIVED', dbName: null },
        ],
      },
