    const result = generateEnumTypes(enums)
    expect(result).toContain("export type Role = 'ADMIN' | 'USER'")
    expect(result).toContain("export type Status = 'DRAFT' | 'PUBLISHED' | 'ARCHIVED'")
  })

  test('returns empty string for no enums', () => {
    expect(generateEnumTypes([])).toBe('')
  })
})

