import type { Model } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateModelDelegates } from './generate-model-delegate'

function makeModel(overrides: Partial<Model> = {}): Model {
  return {
    name: 'User',
    dbName: null,
    schema: null,
    fields: [
      {
        kind: 'scalar',
        name: 'id',
        isRequired: true,
        isList: false,
        isUnique: false,
        isId: true,
        isReadOnly: false,
        type: 'String',
        hasDefaultValue: true,
        default: { name: 'uuid', args: [] },
      },
      {
        kind: 'scalar',
        name: 'email',
        isRequired: true,
        isList: false,
        isUnique: false,
        isId: false,
        isReadOnly: false,
        type: 'String',
        hasDefaultValue: false,
      },
    ],
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    ...overrides,
  } as Model
}

describe('generateModelDelegates', () => {
  test('generates a delegate class with all CRUD methods for a model with @id', () => {
    const result = generateModelDelegates([makeModel()])

    expect(result).toContain('export class UserDelegate {')
    expect(result).toContain('async findMany(')
    expect(result).toContain('async findUnique(')
    expect(result).toContain('async create(')
    expect(result).toContain('async update(')
    expect(result).toContain('async delete(')
  })

  test('generates type imports from ./types', () => {
    const result = generateModelDelegates([makeModel()])

    expect(result).toContain("import type { User, UserWhereInput, UserCreateInput, UserUpdateInput } from './types'")
  })

  test('uses Pick<Model, id> for where clauses with single @id', () => {
    const result = generateModelDelegates([makeModel()])

    expect(result).toContain("Pick<User, 'id'>")
  })

  test('uses REST endpoints based on lowercase model name', () => {
    const result = generateModelDelegates([makeModel()])

    expect(result).toContain('/user')
  })

  test('generates only findMany and create when model has no unique key', () => {
    const model = makeModel({
      fields: [
        {
          kind: 'scalar',
          name: 'value',
          isRequired: true,
          isList: false,
          isUnique: false,
          isId: false,
          isReadOnly: false,
          type: 'String',
          hasDefaultValue: false,
        },
      ],
      primaryKey: null,
      uniqueFields: [],
    } as Partial<Model>)

    const result = generateModelDelegates([model])

    expect(result).toContain('async findMany(')
    expect(result).toContain('async create(')
    expect(result).not.toContain('async findUnique(')
    expect(result).not.toContain('async update(')
    expect(result).not.toContain('async delete(')
  })

  test('handles composite primary key with @@id', () => {
    const model = makeModel({
      name: 'PostTag',
      fields: [
        {
          kind: 'scalar',
          name: 'postId',
          isRequired: true,
          isList: false,
          isUnique: false,
          isId: false,
          isReadOnly: false,
          type: 'String',
          hasDefaultValue: false,
        },
        {
          kind: 'scalar',
          name: 'tagId',
          isRequired: true,
          isList: false,
          isUnique: false,
          isId: false,
          isReadOnly: false,
          type: 'String',
          hasDefaultValue: false,
        },
      ],
      primaryKey: { name: null, fields: ['postId', 'tagId'] },
      uniqueFields: [],
    } as Partial<Model>)

    const result = generateModelDelegates([model])

    expect(result).toContain("Pick<PostTag, 'postId' | 'tagId'>")
    expect(result).toContain('async findUnique(')
    expect(result).toContain('async update(')
    expect(result).toContain('async delete(')
  })

  test('falls back to @@unique when no @id or @@id exists', () => {
    const model = makeModel({
      name: 'Session',
      fields: [
        {
          kind: 'scalar',
          name: 'token',
          isRequired: true,
          isList: false,
          isUnique: false,
          isId: false,
          isReadOnly: false,
          type: 'String',
          hasDefaultValue: false,
        },
      ],
      primaryKey: null,
      uniqueFields: [['token']],
    } as Partial<Model>)

    const result = generateModelDelegates([model])

    expect(result).toContain("Pick<Session, 'token'>")
    expect(result).toContain('async findUnique(')
  })
})

